import { NextResponse } from "next/server";
import { db } from "@/lib/db";

export async function GET() {
    try {
        const bookings = await db.bookings.findAll();
        const leads = await db.leads.findAll();

        // Join bookings with lead data
        const bookingsWithLeads = bookings.map(booking => {
            const lead = leads.find(l => l.id === booking.leadId);
            return {
                ...booking,
                lead: lead ? { name: `${lead.firstName} ${lead.lastName}`, phone: lead.phone } : null
            };
        });

        return NextResponse.json(bookingsWithLeads);
    } catch (error) {
        console.error("Failed to fetch bookings:", error);
        return NextResponse.json({ error: "Failed to fetch bookings" }, { status: 500 });
    }
}

export async function POST(req: Request) {
    try {
        const body = await req.json();
        // Reuse the logic from [id]/bookings or just implement simple create here
        // For now, let's just return 501 Not Implemented as we use the lead-specific endpoint
        return NextResponse.json({ error: "Use /api/leads/[id]/bookings for creation" }, { status: 501 });
    } catch (error) {
        return NextResponse.json({ error: "Error" }, { status: 500 });
    }
}

