import { NextRequest, NextResponse } from 'next/server';
import { db, Activity } from '@/lib/db';
import { v4 as uuidv4 } from 'uuid';

export async function POST(
    request: NextRequest,
    { params }: { params: { id: string } }
) {
    try {
        const body = await request.json();

        if (!body.type || !body.summary) {
            return NextResponse.json(
                { error: 'Missing required fields' },
                { status: 400 }
            );
        }

        const lead = db.leads.findById(params.id);
        if (!lead) {
            return NextResponse.json(
                { error: 'Lead not found' },
                { status: 404 }
            );
        }

        const newActivity: Activity = {
            id: uuidv4(),
            leadId: params.id,
            type: body.type,
            summary: body.summary,
            createdAt: new Date().toISOString(),
            payload: body.payload
        };

        const createdActivity = db.activities.create(newActivity);

        // Update last contacted if it's an interaction
        if (['ai_call', 'whatsapp', 'manual_call'].includes(body.type)) {
            db.leads.update(params.id, { lastContactedAt: new Date().toISOString() });
        }

        return NextResponse.json(createdActivity, { status: 201 });
    } catch (error) {
        return NextResponse.json(
            { error: 'Invalid request body' },
            { status: 400 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { db, Booking, Activity } from '@/lib/db';
import { v4 as uuidv4 } from 'uuid';

export async function POST(
    request: NextRequest,
    { params }: { params: { id: string } }
) {
    try {
        const body = await request.json();
        const { scheduledAt, propertyId } = body;

        if (!scheduledAt) {
            return NextResponse.json(
                { error: 'Scheduled time is required' },
                { status: 400 }
            );
        }

        const lead = db.leads.findById(params.id);
        if (!lead) {
            return NextResponse.json(
                { error: 'Lead not found' },
                { status: 404 }
            );
        }

        // Create booking
        const booking: Booking = {
            id: uuidv4(),
            leadId: params.id,
            propertyId,
            scheduledAt,
            status: 'confirmed',
            createdAt: new Date().toISOString()
        };
        db.bookings.create(booking);

        // Update lead status to Visit Booked
        db.leads.update(params.id, { status: 'Visit Booked' });

        // Log booking activity
        const activity: Activity = {
            id: uuidv4(),
            leadId: params.id,
            type: 'booking',
            summary: `Visit booked for ${new Date(scheduledAt).toLocaleString()}`,
            createdAt: new Date().toISOString(),
            payload: booking
        };
        db.activities.create(activity);

        return NextResponse.json(booking, { status: 201 });
    } catch (error) {
        return NextResponse.json(
            { error: 'Invalid request body' },
            { status: 400 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';

export async function GET(
    request: NextRequest,
    { params }: { params: { id: string } }
) {
    const lead = db.leads.findById(params.id);

    if (!lead) {
        return NextResponse.json(
            { error: 'Lead not found' },
            { status: 404 }
        );
    }

    const activities = db.activities.findByLeadId(params.id);

    return NextResponse.json({
        ...lead,
        activities
    });
}

export async function PUT(
    request: NextRequest,
    { params }: { params: { id: string } }
) {
    try {
        const body = await request.json();
        const updatedLead = db.leads.update(params.id, body);

        if (!updatedLead) {
            return NextResponse.json(
                { error: 'Lead not found' },
                { status: 404 }
            );
        }

        return NextResponse.json(updatedLead);
    } catch (error) {
        return NextResponse.json(
            { error: 'Invalid request body' },
            { status: 400 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { db, Activity } from '@/lib/db';
import { v4 as uuidv4 } from 'uuid';

export async function POST(
    request: NextRequest,
    { params }: { params: { id: string } }
) {
    try {
        const body = await request.json();
        const { status, reason } = body;

        if (!status) {
            return NextResponse.json(
                { error: 'Status is required' },
                { status: 400 }
            );
        }

        const lead = db.leads.findById(params.id);
        if (!lead) {
            return NextResponse.json(
                { error: 'Lead not found' },
                { status: 404 }
            );
        }

        const oldStatus = lead.status;

        // Update lead status
        db.leads.update(params.id, { status });

        // Log status change activity
        const activity: Activity = {
            id: uuidv4(),
            leadId: params.id,
            type: 'status_change',
            summary: `Status changed: ${oldStatus} → ${status}`,
            createdAt: new Date().toISOString(),
            payload: { oldStatus, newStatus: status, reason }
        };
        db.activities.create(activity);

        return NextResponse.json({ success: true, status });
    } catch (error) {
        return NextResponse.json(
            { error: 'Invalid request body' },
            { status: 400 }
        );
    }
}

"use client";

import { useState, useEffect } from "react";
import { Booking } from "@/lib/db";
import { Calendar as CalendarIcon, MapPin, Clock, User, ChevronLeft, ChevronRight } from "lucide-react";
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameMonth, isSameDay, addMonths, subMonths, isToday, startOfWeek, endOfWeek } from "date-fns";

type BookingWithLead = Booking & {
    lead?: { name: string; phone: string } | null;
};

export default function CalendarPage() {
    const [bookings, setBookings] = useState<BookingWithLead[]>([]);
    const [loading, setLoading] = useState(true);
    const [currentDate, setCurrentDate] = useState(new Date());

    useEffect(() => {
        fetchBookings();
    }, []);

    const fetchBookings = async () => {
        try {
            const res = await fetch('/api/bookings');
            const data = await res.json();
            setBookings(data);
        } catch (error) {
            console.error("Failed to fetch calendar data", error);
        } finally {
            setLoading(false);
        }
    };

    const nextMonth = () => setCurrentDate(addMonths(currentDate, 1));
    const prevMonth = () => setCurrentDate(subMonths(currentDate, 1));

    const monthStart = startOfMonth(currentDate);
    const monthEnd = endOfMonth(currentDate);
    const startDate = startOfWeek(monthStart);
    const endDate = endOfWeek(monthEnd);

    const calendarDays = eachDayOfInterval({ start: startDate, end: endDate });

    return (
        <div className="p-8 max-w-7xl mx-auto h-full flex flex-col">
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold font-heading text-slate-900">Calendar</h1>
                    <p className="text-slate-500 mt-1">Manage your site visits and appointments</p>
                </div>
                <div className="flex items-center gap-4 bg-white p-1 rounded-xl border border-slate-200 shadow-sm">
                    <button onClick={prevMonth} className="p-2 hover:bg-slate-100 rounded-lg text-slate-600">
                        <ChevronLeft size={20} />
                    </button>
                    <span className="font-bold text-slate-900 w-32 text-center">
                        {format(currentDate, "MMMM yyyy")}
                    </span>
                    <button onClick={nextMonth} className="p-2 hover:bg-slate-100 rounded-lg text-slate-600">
                        <ChevronRight size={20} />
                    </button>
                </div>
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 flex-1 flex flex-col overflow-hidden">
                {/* Days Header */}
                <div className="grid grid-cols-7 border-b border-slate-200 bg-slate-50">
                    {["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].map(day => (
                        <div key={day} className="py-3 text-center text-sm font-medium text-slate-500">
                            {day}
                        </div>
                    ))}
                </div>

                {/* Calendar Grid */}
                <div className="grid grid-cols-7 flex-1 auto-rows-fr">
                    {calendarDays.map(day => {
                        const dayBookings = bookings.filter(b => isSameDay(new Date(b.date), day));
                        const isCurrentMonth = isSameMonth(day, currentDate);

                        return (
                            <div
                                key={day.toISOString()}
                                className={`min-h-[100px] p-2 border-b border-r border-slate-100 transition-colors hover:bg-slate-50 ${!isCurrentMonth ? 'bg-slate-50/50 text-slate-400' : ''
                                    } ${isToday(day) ? 'bg-indigo-50/30' : ''}`}
                            >
                                <div className="flex justify-between items-start mb-2">
                                    <span className={`text-sm font-medium w-7 h-7 flex items-center justify-center rounded-full ${isToday(day) ? 'bg-indigo-600 text-white' : (!isCurrentMonth ? 'text-slate-400' : 'text-slate-700')
                                        }`}>
                                        {format(day, "d")}
                                    </span>
                                    {dayBookings.length > 0 && (
                                        <span className="text-xs font-bold text-indigo-600 bg-indigo-100 px-1.5 py-0.5 rounded-md">
                                            {dayBookings.length}
                                        </span>
                                    )}
                                </div>

                                <div className="space-y-1 overflow-y-auto max-h-[80px]">
                                    {dayBookings.map(booking => (
                                        <div key={booking.id} className="text-xs p-1.5 bg-indigo-50 text-indigo-700 rounded-md border border-indigo-100 truncate cursor-pointer hover:bg-indigo-100 transition-colors">
                                            <div className="font-medium truncate">{booking.time} - {booking.lead?.name || "Unknown"}</div>
                                            <div className="text-indigo-500/80 truncate text-[10px]">{booking.propertyId}</div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Database } from "lucide-react";

export default function DebugPage() {
    const [data, setData] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetch('/api/debug')
            .then(res => res.json())
            .then(data => setData(data))
            .catch(err => console.error(err))
            .finally(() => setLoading(false));
    }, []);

    if (loading) return <div className="p-8">Loading data...</div>;

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8">
            <div className="flex items-center gap-4">
                <div className="p-3 bg-slate-900 text-white rounded-xl">
                    <Database size={24} />
                </div>
                <div>
                    <h1 className="text-3xl font-bold font-heading text-slate-900">System Data</h1>
                    <p className="text-slate-500">Raw view of the local database for verification</p>
                </div>
            </div>

            <div className="space-y-8">
                {Object.keys(data || {}).map(key => (
                    <div key={key} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
                        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                            <h2 className="text-lg font-bold text-slate-900 capitalize">{key}</h2>
                            <span className="text-xs font-medium px-2.5 py-1 bg-slate-200 text-slate-700 rounded-full">
                                {data[key].length} items
                            </span>
                        </div>
                        <div className="p-0 overflow-x-auto">
                            <pre className="text-xs text-slate-600 p-4 font-mono">
                                {JSON.stringify(data[key], null, 2)}
                            </pre>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Lead, Activity } from "@/lib/db";
import { useParams } from "next/navigation";
import { Phone, Mail, User, ArrowLeft, MessageSquare, Calendar, ChevronDown, Check, Clock, Tag } from "lucide-react";
import Link from "next/link";
import { cn } from "@/lib/utils";
import ActivityTimeline from "@/components/ActivityTimeline";
import ActivityComposer from "@/components/ActivityComposer";
import BookingModal from "@/components/BookingModal";

export default function LeadProfile() {
    const params = useParams();
    const [lead, setLead] = useState<Lead | null>(null);
    const [activities, setActivities] = useState<Activity[]>([]);
    const [loading, setLoading] = useState(true);
    const [isBookingOpen, setIsBookingOpen] = useState(false);
    const [isStatusOpen, setIsStatusOpen] = useState(false);

    useEffect(() => {
        if (params.id) {
            fetchLeadDetails();
        }
    }, [params.id]);

    const fetchLeadDetails = async () => {
        try {
            const res = await fetch(`/api/leads/${params.id}`);
            const data = await res.json();
            setLead(data);
            setActivities(data.activities || []);
        } catch (error) {
            console.error("Failed to fetch lead details", error);
        } finally {
            setLoading(false);
        }
    };

    const handleActivityAdded = (newActivity: Activity) => {
        setActivities([newActivity, ...activities]);
        fetchLeadDetails(); // Refresh to update status/lastContacted
    };

    const handleStatusChange = async (newStatus: string) => {
        if (!lead) return;
        try {
            const res = await fetch(`/api/leads/${lead.id}/status`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ status: newStatus })
            });

            if (res.ok) {
                fetchLeadDetails();
                setIsStatusOpen(false);
            }
        } catch (error) {
            console.error("Failed to update status", error);
        }
    };

    if (loading) return <div className="flex h-full items-center justify-center text-slate-400">Loading profile...</div>;
    if (!lead) return <div className="flex h-full items-center justify-center text-slate-400">Lead not found</div>;

    const statusOptions = [
        "New", "Contacted", "AI-Qualified", "Human Verified", "Property Suggested",
        "Visit Booked", "Visit Completed", "Follow-Up Stage", "Negotiation Stage",
        "Token Paid", "Closed (Won)", "Closed (Lost)", "No-Show"
    ];

    const statusColors: Record<string, string> = {
        "New": "bg-blue-50 text-blue-700 ring-blue-600/20",
        "Contacted": "bg-indigo-50 text-indigo-700 ring-indigo-600/20",
        "AI-Qualified": "bg-purple-50 text-purple-700 ring-purple-600/20",
        "Human Verified": "bg-violet-50 text-violet-700 ring-violet-600/20",
        "Property Suggested": "bg-sky-50 text-sky-700 ring-sky-600/20",
        "Visit Booked": "bg-orange-50 text-orange-700 ring-orange-600/20",
        "Visit Completed": "bg-amber-50 text-amber-700 ring-amber-600/20",
        "Follow-Up Stage": "bg-yellow-50 text-yellow-700 ring-yellow-600/20",
        "Negotiation Stage": "bg-pink-50 text-pink-700 ring-pink-600/20",
        "Token Paid": "bg-emerald-50 text-emerald-700 ring-emerald-600/20",
        "Closed (Won)": "bg-green-50 text-green-700 ring-green-600/20",
        "Closed (Lost)": "bg-slate-100 text-slate-500 ring-slate-600/20",
        "No-Show": "bg-red-50 text-red-700 ring-red-600/20",
    };

    return (
        <div className="p-8 max-w-7xl mx-auto">
            {/* Back Link */}
            <Link href="/" className="inline-flex items-center gap-2 text-sm text-slate-500 hover:text-slate-900 mb-6 transition-colors group">
                <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" />
                Back to Leads
            </Link>

            {/* Header Card */}
            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-8 mb-8 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                    <div>
                        <div className="flex items-center gap-4 mb-3">
                            <h1 className="text-3xl font-bold font-heading text-slate-900">{lead.firstName} {lead.lastName}</h1>

                            {/* Status Dropdown */}
                            <div className="relative">
                                <button
                                    onClick={() => setIsStatusOpen(!isStatusOpen)}
                                    className={cn("px-3 py-1 rounded-full text-sm font-medium flex items-center gap-1.5 transition-all ring-1 ring-inset hover:ring-2", statusColors[lead.status] || "bg-slate-100 text-slate-700")}
                                >
                                    {lead.status}
                                    <ChevronDown size={14} className="opacity-70" />
                                </button>

                                {isStatusOpen && (
                                    <div className="absolute top-full left-0 mt-2 w-64 bg-white rounded-xl shadow-xl border border-slate-100 py-2 z-20 animate-in fade-in zoom-in-95 duration-100 max-h-96 overflow-y-auto">
                                        {statusOptions.map((status) => (
                                            <button
                                                key={status}
                                                onClick={() => handleStatusChange(status)}
                                                className="w-full text-left px-4 py-2.5 text-sm text-slate-700 hover:bg-slate-50 flex items-center justify-between transition-colors"
                                            >
                                                {status}
                                                {lead.status === status && <Check size={14} className="text-indigo-600" />}
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Score Badge */}
                            <div className="px-2.5 py-1 bg-indigo-50 text-indigo-700 rounded-lg text-xs font-bold border border-indigo-100 flex items-center gap-1">
                                Score: {lead.score || 0}
                            </div>
                        </div>

                        <div className="flex flex-wrap items-center gap-6 text-slate-500 text-sm">
                            <div className="flex items-center gap-2">
                                <div className="p-1.5 bg-slate-100 rounded-full"><Phone size={14} className="text-slate-600" /></div>
                                <span className="font-medium text-slate-700">{lead.phone}</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <div className="p-1.5 bg-slate-100 rounded-full"><Mail size={14} className="text-slate-600" /></div>
                                <span>{lead.email || "No email"}</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <div className="p-1.5 bg-slate-100 rounded-full"><User size={14} className="text-slate-600" /></div>
                                <span>{lead.source || "Manual"}</span>
                            </div>
                        </div>
                    </div>

                    <div className="flex gap-3 w-full md:w-auto">
                        <button className="flex-1 md:flex-none btn-primary flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700 hover:shadow-emerald-500/30">
                            <Phone size={18} />
                            Call
                        </button>
                        <button className="flex-1 md:flex-none btn-secondary flex items-center justify-center gap-2">
                            <MessageSquare size={18} />
                            WhatsApp
                        </button>
                        <button
                            onClick={() => setIsBookingOpen(true)}
                            className="flex-1 md:flex-none btn-primary flex items-center justify-center gap-2"
                        >
                            <Calendar size={18} />
                            Book Visit
                        </button>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Left Column: Info */}
                <div className="space-y-8">
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                        <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider mb-6 flex items-center gap-2">
                            <User size={16} className="text-indigo-500" />
                            Lead Details
                        </h3>
                        <div className="space-y-6">
                            <div className="pb-4 border-b border-slate-50">
                                <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider block mb-1.5">Budget Range</label>
                                <div className="text-lg font-medium text-slate-900">
                                    {lead.budgetMin ? `₹${(lead.budgetMin / 100000).toFixed(0)}L - ${(lead.budgetMax! / 100000).toFixed(0)}L` : "-"}
                                </div>
                            </div>
                            <div className="pb-4 border-b border-slate-50">
                                <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider block mb-1.5">Location Preference</label>
                                <div className="flex items-center gap-2 text-slate-900 font-medium">
                                    <MapPin size={16} className="text-slate-400" />
                                    {lead.preferredLocation || "Not specified"}
                                </div>
                            </div>
                            <div>
                                <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider block mb-2">Tags</label>
                                <div className="flex flex-wrap gap-2">
                                    {lead.tags?.map(tag => (
                                        <span key={tag} className="px-2.5 py-1 bg-slate-100 text-slate-600 rounded-lg text-xs font-medium border border-slate-200 flex items-center gap-1">
                                            <Tag size={10} />
                                            {tag}
                                        </span>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Right Column: Activity & Composer */}
                <div className="lg:col-span-2 space-y-8">
                    {/* Composer */}
                    <ActivityComposer leadId={lead.id} onActivityAdded={handleActivityAdded} />

                    {/* Timeline */}
                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-8">
                        <h3 className="text-lg font-bold font-heading text-slate-900 mb-8 flex items-center gap-2">
                            <Clock size={20} className="text-indigo-500" />
                            Activity Timeline
                        </h3>
                        <ActivityTimeline activities={activities} />
                    </div>
                </div>
            </div>

            <BookingModal
                isOpen={isBookingOpen}
                onClose={() => setIsBookingOpen(false)}
                leadId={params.id as string}
                onBookingConfirmed={handleActivityAdded}
            />
        </div>
    );
}

"use client";

import { useState } from "react";
import { Activity } from "@/lib/db";
import { Phone, MessageSquare, Calendar, StickyNote, Send } from "lucide-react";
import { cn } from "@/lib/utils";

interface ActivityComposerProps {
    leadId: string;
    onActivityAdded: (activity: Activity) => void;
}

export default function ActivityComposer({ leadId, onActivityAdded }: ActivityComposerProps) {
    const [activeTab, setActiveTab] = useState<"note" | "call" | "whatsapp">("note");
    const [note, setNote] = useState("");
    const [submitting, setSubmitting] = useState(false);

    const handleSubmit = async () => {
        if (!note.trim()) return;
        setSubmitting(true);

        try {
            const typeMap = {
                note: "note",
                call: "manual_call",
                whatsapp: "whatsapp"
            };

            const res = await fetch(`/api/leads/${leadId}/activities`, {
