                    className={cn("flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 transition-colors", activeTab === "call" ? "bg-gray-50 text-blue-600 border-b-2 border-blue-600" : "text-gray-500 hover:bg-gray-50")}
