import fs from 'fs';
import path from 'path';

const DB_PATH = path.join(process.cwd(), 'data', 'db.json');

export type LeadStatus =
    | "New"
    | "Contacted"
    | "AI-Qualified"
    | "Human Verified"
    | "Property Suggested"
    | "Visit Booked"
    | "Visit Completed"
    | "Follow-Up Stage"
    | "Negotiation Stage"
    | "Token Paid"
    | "Closed (Won)"
    | "Closed (Lost)"
    | "No-Show";

export interface Lead {
    id: string;
    firstName: string;
    lastName: string;
    email: string;
    phone: string;
    altPhone?: string;
    budgetMin?: number;
    budgetMax?: number;
    preferredLocation?: string;
    unitType?: "1BHK" | "2BHK" | "3BHK" | "Duplex" | "Villa";
    source?: string;
    preferredLanguage?: string;
    tags?: string[];
    score?: number;
    assignedSalespersonId?: string;
    status: LeadStatus;
    qualificationRating?: "A" | "B" | "C";
    createdAt: string;
    updatedAt: string;
    lastContactedAt?: string;
}

export interface Activity {
    id: string;
    leadId: string;
    type: 'form_submission' | 'ai_call' | 'whatsapp' | 'booking' | 'status_change' | 'note';
    summary: string;
    createdAt: string;
    payload?: any;
}

export interface Booking {
    id: string;
    leadId: string;
    propertyId?: string;
    scheduledAt: string;
    status: 'confirmed' | 'completed' | 'no_show' | 'cancelled';
    confirmedBy?: string;
    createdAt: string;
}

export interface Property {
    id: string;
    name: string;
    location: string;
}

export interface User {
    id: string;
    name: string;
    email: string;
    role: 'admin' | 'sales' | 'viewer';
}

export interface DatabaseSchema {
    users: User[];
    leads: Lead[];
    activities: Activity[];
    bookings: Booking[];
    properties: Property[];
}

function readDb(): DatabaseSchema {
    if (!fs.existsSync(DB_PATH)) {
        return { users: [], leads: [], activities: [], bookings: [], properties: [] };
    }
    const data = fs.readFileSync(DB_PATH, 'utf-8');
    return JSON.parse(data);
}

function writeDb(data: DatabaseSchema) {
    fs.writeFileSync(DB_PATH, JSON.stringify(data, null, 2));
}

export const db = {
    users: {
        findAll: () => readDb().users,
        findById: (id: string) => readDb().users.find((u) => u.id === id),
    },
    leads: {
        findAll: () => readDb().leads,
        findById: (id: string) => readDb().leads.find((l) => l.id === id),
        create: (lead: Lead) => {
            const data = readDb();
            data.leads.push(lead);
            writeDb(data);
            return lead;
        },
        update: (id: string, updates: Partial<Lead>) => {
            const data = readDb();
            const index = data.leads.findIndex((l) => l.id === id);
            if (index === -1) return null;
            data.leads[index] = { ...data.leads[index], ...updates };
            writeDb(data);
            return data.leads[index];
        },
    },
    activities: {
        findAll: () => readDb().activities,
        findByLeadId: (leadId: string) => readDb().activities.filter((a) => a.leadId === leadId).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()),
        create: (activity: Activity) => {
            const data = readDb();
            data.activities.push(activity);
            writeDb(data);
            return activity;
        },
    },
    bookings: {
        findAll: () => readDb().bookings,
        create: (booking: Booking) => {
            const data = readDb();
            data.bookings.push(booking);
            writeDb(data);
            return booking;
        }
    }
};

